/**
 * Dispatch a notification payload through all registered adapters.
 * Queues dispatches to guarantee FIFO ordering — concurrent calls are serialized
 * so notifications are delivered in the order they were triggered.
 */
private dispatch(payload: NotificationPayload): Promise<void> {
  const task = this.dispatchQueue.then(() => this.processDispatch(payload));
  // Prevent a failed dispatch from blocking subsequent dispatches
  this.dispatchQueue = task.catch(() => {});
  return task;
}

/**
 * Process a single notification dispatch through all registered adapters.
 * Checks user preferences per channel before sending (if PreferencesService is set).
 * If no adapters are registered, stores the notification with channel 'email' as a fallback record.
 */
private async processDispatch(payload: NotificationPayload): Promise<void> {
  const userId = payload.metadata?.['userId'] as string | undefined;

  if (this.adapters.length === 0) {
    // Check preferences before storing the fallback record
    if (userId && this.preferencesService && !this.preferencesService.isChannelEnabled(userId, 'email', payload.type)) {
      this.logger.info(`Notification suppressed for user ${userId}: ${payload.type} (email disabled)`);
      return;
    }
    // No adapters registered — store as in-memory record for backward compatibility
    this.storeNotification(payload, 'email', true);
    return;
  }

  for (const adapter of this.adapters) {
    // Check per-channel preferences
    if (userId && this.preferencesService) {
      if (!this.preferencesService.isChannelEnabled(userId, adapter.channel, payload.type)) {
        this.logger.info(
          `Notification suppressed for user ${userId}: ${payload.type} (${adapter.channel} disabled)`,
        );
        continue;
      }
    }

    const result = await adapter.send(payload);
    this.storeNotification(payload, adapter.channel, result.success, result.error);
  }
}

